import React from 'react';

const EditorToolbar = ({ onFormat, onChange, value }) => {
  const insertText = (before, after, selection) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const start = selection ? selection.start : textarea.selectionStart;
    const end = selection ? selection.end : textarea.selectionEnd;

    const text = value || '';
    const newText = text.substring(0, start) + before + text.substring(start, end) + after + text.substring(end);

    // Call onChange to update React state
    onChange(newText);

    // Restore cursor position after React re-renders
    setTimeout(() => {
      const updatedTextarea = document.querySelector('.markdown-editor');
      if (updatedTextarea) {
        // For code formatting, place cursor after the closing backtick
        // For other formatting, place cursor after the closing tag
        const newCursorPos = start + before.length + (end - start) + after.length;
        updatedTextarea.focus();
        updatedTextarea.setSelectionRange(newCursorPos, newCursorPos);
      }
    }, 0);
  };

  const wrapSelection = (before, after) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const selection = {
      start: textarea.selectionStart,
      end: textarea.selectionEnd
    };

    insertText(before, after, selection);
  };

  const handleBold = () => wrapSelection('**', '**');
  const handleItalic = () => wrapSelection('*', '*');
  const handleHeading = (level) => wrapSelection('#'.repeat(level) + ' ', '');
  const handleCode = () => wrapSelection('`', '`');
  const handleList = (ordered) => {
    const textarea = document.querySelector('.markdown-editor');
    if (!textarea) return;

    const text = value || '';
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;

    // Find the start and end of the current paragraph/lines
    const textBeforeStart = text.substring(0, start);
    const textAfterEnd = text.substring(end);

    const linesBeforeStart = textBeforeStart.split('\n');
    const linesAfterEnd = textAfterEnd.split('\n');

    // Find line boundaries
    const currentLineIndex = linesBeforeStart.length - 1;
    const currentLineStart = textBeforeStart.lastIndexOf('\n') + 1;

    // Find end of current paragraph (next empty line or end of text)
    const remainingText = text.substring(currentLineStart);
    const lines = remainingText.split('\n');
    let endLineIndex = 0;

    for (let i = 0; i < lines.length; i++) {
      if (lines[i].trim() === '' && i > 0) {
        break;
      }
      endLineIndex = i;
    }

    // Get the text to format (current paragraph)
    const paragraphEnd = currentLineStart + lines.slice(0, endLineIndex + 1).join('\n').length;
    const textToFormat = text.substring(currentLineStart, paragraphEnd);

    // Format each line in the paragraph
    const linesToFormat = textToFormat.split('\n');
    const formattedLines = linesToFormat.map((line, index) => {
      const indentation = line.match(/^\s*/)[0] || '';
      const content = line.trim();

      if (ordered) {
        return `${indentation}${index + 1}. ${content}`;
      } else {
        return `${indentation}- ${content}`;
      }
    });

    const newText = text.substring(0, currentLineStart) +
      formattedLines.join('\n') +
      text.substring(paragraphEnd);

    // Update the text and restore cursor position
    onChange(newText);

    setTimeout(() => {
      const updatedTextarea = document.querySelector('.markdown-editor');
      if (updatedTextarea) {
        updatedTextarea.focus();
        updatedTextarea.setSelectionRange(paragraphEnd, paragraphEnd);
      }
    }, 0);
  };

  return (
    <div className="editor-toolbar">
      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={handleBold}
          title="Bold (Ctrl+B)"
        >
          <strong>B</strong>
        </button>
        <button
          className="toolbar-btn"
          onClick={handleItalic}
          title="Italic (Ctrl+I)"
        >
          <em>I</em>
        </button>
      </div>

      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(1)}
          title="Heading 1 (Ctrl+1)"
        >
          H1
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(2)}
          title="Heading 2 (Ctrl+2)"
        >
          H2
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleHeading(3)}
          title="Heading 3 (Ctrl+3)"
        >
          H3
        </button>
      </div>

      <div className="toolbar-group">
        <button
          className="toolbar-btn"
          onClick={() => handleList(false)}
          title="Bullet List (Ctrl+L)"
        >
          • List
        </button>
        <button
          className="toolbar-btn"
          onClick={() => handleList(true)}
          title="Numbered List (Ctrl+Shift+L)"
        >
          1. List
        </button>
        <button
          className="toolbar-btn"
          onClick={handleCode}
          title="Code (Ctrl+K)"
        >
          {'</>'}
        </button>
      </div>
    </div>
  );
};

export default EditorToolbar;
